```go
package main

import (
	"encoding/json"
	"errors"
	"io"
	"log"
	"net/http"
)

// SECURE: Strongly typed structs with explicit fields
type UserAction struct {
	Action   string          `json:"action"`
	UserID   int64           `json:"user_id"`
	Metadata *ActionMetadata `json:"metadata,omitempty"`
}

type ActionMetadata struct {
	Source    string `json:"source"`
	Timestamp int64  `json:"timestamp"`
}

// SECURE: Whitelist of allowed actions
var allowedActions = map[string]bool{
	"view_profile": true,
	"update_email": true,
	"logout":       true,
}

const maxRequestSize = 1024 * 10 // 10KB limit

func handleActionSecure(w http.ResponseWriter, r *http.Request) {
	// SECURE: Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxRequestSize)

	var action UserAction
	decoder := json.NewDecoder(r.Body)
	// SECURE: Reject unknown fields
	decoder.DisallowUnknownFields()

	if err := decoder.Decode(&action); err != nil {
		log.Printf("Invalid JSON from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid request format", http.StatusBadRequest)
		return
	}

	// SECURE: Validate against whitelist
	if err := validateAction(&action); err != nil {
		log.Printf("Invalid action from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Action not permitted", http.StatusForbidden)
		return
	}

	// Process validated action safely
	processAction(action)
	w.WriteHeader(http.StatusOK)
}

func validateAction(action *UserAction) error {
	if !allowedActions[action.Action] {
		return errors.New("action not in whitelist")
	}
	if action.UserID <= 0 {
		return errors.New("invalid user ID")
	}
	return nil
}

func processAction(action UserAction) {
	// Safe processing with validated, typed data
}
```

**Key Security Controls**:
- **Strongly typed structs**: No `interface{}` fields - all data types are explicit and known at compile time
- **Request size limits**: `MaxBytesReader` prevents memory exhaustion attacks
- **DisallowUnknownFields**: Rejects JSON with unexpected properties that could indicate attack attempts
- **Action whitelist**: Only pre-approved actions are processed, preventing arbitrary command injection

Polymorphic deserialization is where many vulnerabilities hide. The key is to use a discriminator pattern with explicit type mapping rather than allowing arbitrary type resolution. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"sync"
	"time"

	"github.com/google/uuid"
)

// Security configuration
const (
	maxRequestSize     = 64 * 1024 // 64KB
	maxNestingDepth    = 10
	requestTimeout     = 30 * time.Second
)

// Base message with type discriminator
type Message struct {
	Type      string          `json:"type"`
	RequestID string          `json:"request_id"`
	Timestamp int64           `json:"timestamp"`
	Payload   json.RawMessage `json:"payload"` // Deferred parsing
}

// Strongly typed payload structs - NO interface{}
type UserUpdatePayload struct {
	UserID int64  `json:"user_id"`
	Email  string `json:"email"`
	Name   string `json:"name"`
}

type OrderPayload struct {
	OrderID   string  `json:"order_id"`
	ProductID string  `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price"`
}

type NotificationPayload struct {
	Channel string `json:"channel"`
	Message string `json:"message"`
	UserIDs []int64 `json:"user_ids"`
}

// Handler interface for type-safe processing
type PayloadHandler interface {
	Validate() error
	Process(ctx context.Context) error
}

// Implement handler for each payload type
func (p *UserUpdatePayload) Validate() error {
	if p.UserID <= 0 {
		return errors.New("invalid user_id")
	}
	if len(p.Email) > 255 || len(p.Name) > 100 {
		return errors.New("field length exceeded")
	}
	return nil
}

func (p *UserUpdatePayload) Process(ctx context.Context) error {
	// Safe processing with validated data
	return nil
}

func (p *OrderPayload) Validate() error {
	if p.Quantity <= 0 || p.Quantity > 1000 {
		return errors.New("invalid quantity")
	}
	if p.Price < 0 || p.Price > 1000000 {
		return errors.New("invalid price")
	}
	return nil
}

func (p *OrderPayload) Process(ctx context.Context) error {
	return nil
}

func (p *NotificationPayload) Validate() error {
	allowedChannels := map[string]bool{"email": true, "sms": true, "push": true}
	if !allowedChannels[p.Channel] {
		return errors.New("invalid notification channel")
	}
	if len(p.UserIDs) > 1000 {
		return errors.New("too many recipients")
	}
	return nil
}

func (p *NotificationPayload) Process(ctx context.Context) error {
	return nil
}

// SECURE: Type registry with explicit mapping
type TypeRegistry struct {
	mu       sync.RWMutex
	handlers map[string]func() PayloadHandler
}

func NewTypeRegistry() *TypeRegistry {
	r := &TypeRegistry{
		handlers: make(map[string]func() PayloadHandler),
	}
	// Whitelist of allowed types
	r.Register("user.update", func() PayloadHandler { return &UserUpdatePayload{} })
	r.Register("order.create", func() PayloadHandler { return &OrderPayload{} })
	r.Register("notification.send", func() PayloadHandler { return &NotificationPayload{} })
	return r
}

func (r *TypeRegistry) Register(typeName string, factory func() PayloadHandler) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.handlers[typeName] = factory
}

func (r *TypeRegistry) GetHandler(typeName string) (PayloadHandler, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	factory, exists := r.handlers[typeName]
	if !exists {
		return nil, fmt.Errorf("unknown message type: %s", typeName)
	}
	return factory(), nil
}

// Secure deserializer with depth limiting
type SecureDeserializer struct {
	registry *TypeRegistry
	logger   *slog.Logger
}

func NewSecureDeserializer(registry *TypeRegistry, logger *slog.Logger) *SecureDeserializer {
	return &SecureDeserializer{registry: registry, logger: logger}
}

func (d *SecureDeserializer) Deserialize(ctx context.Context, r io.Reader) (PayloadHandler, error) {
	// Layer 1: Size limit
	limitedReader := io.LimitReader(r, maxRequestSize)

	var msg Message
	decoder := json.NewDecoder(limitedReader)
	decoder.DisallowUnknownFields()

	if err := decoder.Decode(&msg); err != nil {
		return nil, fmt.Errorf("invalid message format: %w", err)
	}

	// Layer 2: Validate base message
	if err := d.validateBaseMessage(&msg); err != nil {
		return nil, err
	}

	// Layer 3: Type whitelist lookup
	handler, err := d.registry.GetHandler(msg.Type)
	if err != nil {
		d.logger.WarnContext(ctx, "Unknown message type attempted",
			"type", msg.Type,
			"request_id", msg.RequestID)
		return nil, err
	}

	// Layer 4: Deserialize payload into specific type
	payloadDecoder := json.NewDecoder(nil)
	if err := json.Unmarshal(msg.Payload, handler); err != nil {
		return nil, fmt.Errorf("invalid payload for type %s: %w", msg.Type, err)
	}

	// Layer 5: Business validation
	if err := handler.Validate(); err != nil {
		d.logger.WarnContext(ctx, "Payload validation failed",
			"type", msg.Type,
			"error", err.Error())
		return nil, fmt.Errorf("payload validation failed: %w", err)
	}

	d.logger.InfoContext(ctx, "Message deserialized successfully",
		"type", msg.Type,
		"request_id", msg.RequestID)

	return handler, nil
}

func (d *SecureDeserializer) validateBaseMessage(msg *Message) error {
	if msg.Type == "" {
		return errors.New("message type is required")
	}
	if len(msg.Type) > 50 {
		return errors.New("message type too long")
	}
	// Validate request ID format if provided
	if msg.RequestID != "" {
		if _, err := uuid.Parse(msg.RequestID); err != nil {
			return errors.New("invalid request_id format")
		}
	}
	return nil
}

// HTTP handler with full security controls
func (d *SecureDeserializer) HTTPHandler(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), requestTimeout)
	defer cancel()

	// Enforce size limit at HTTP level
	r.Body = http.MaxBytesReader(w, r.Body, maxRequestSize)

	handler, err := d.Deserialize(ctx, r.Body)
	if err != nil {
		d.logger.ErrorContext(ctx, "Deserialization failed",
			"error", err.Error(),
			"remote_addr", r.RemoteAddr)
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	if err := handler.Process(ctx); err != nil {
		d.logger.ErrorContext(ctx, "Processing failed",
			"error", err.Error())
		http.Error(w, "Processing error", http.StatusInternalServerError)
		return
	}

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}

func main() {
	logger := slog.Default()
	registry := NewTypeRegistry()
	deserializer := NewSecureDeserializer(registry, logger)

	http.HandleFunc("/api/message", deserializer.HTTPHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Defense in Depth Layers**:

1. **Size Limiting**: Both at HTTP layer (`MaxBytesReader`) and during parsing (`LimitReader`) to prevent memory exhaustion

2. **Type Registry Whitelist**: Only explicitly registered types can be deserialized - no dynamic type resolution

3. **Deferred Parsing with `json.RawMessage`**: Payload is validated for type before parsing, preventing gadget chain attacks

4. **Strict Struct Validation**: Each payload type implements explicit validation rules with bounds checking

5. **Structured Logging**: All deserialization attempts are logged with context for security monitoring

**Additional Protections**:
- **Context timeouts**: Prevents slow-loris style attacks during processing
- **DisallowUnknownFields**: Rejects payloads with unexpected fields that could indicate fuzzing or exploitation attempts  
- **UUID validation for request IDs**: Prevents injection through metadata fields
- **Interface-based handlers**: Compile-time enforcement of Validate/Process pattern prevents missing validation
- **No reflection-based deserialization**: All type mappings are explicit, eliminating gadget chain vulnerabilities common in Java/PHP serialization attacks

Deserializing untrusted data is one of the most dangerous operations in software development. The node-serialize library and similar serialization approaches can execute arbitrary code during deserialization, leading to complete server compromise.

**VULNERABLE CODE**:

