    // JWT verification - cryptographically signed, cannot be tampered
    const sessionData = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],  // Explicitly specify allowed algorithms
      maxAge: '1h'            // Token expiration
    });

    // Additional validation even after JWT verification
    if (!validateSession(sessionData)) {
      console.error('Invalid session structure:', validateSession.errors);
      return res.status(400).json({ error: 'Invalid session data' });
    }

    res.json({
      username: sessionData.username,
      preferences: sessionData.preferences
    });
  } catch (err) {
    console.error('JWT verification failed:', err.message);
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
});

// SECURE: Use JSON with strict schema validation
app.post('/api/import-settings', (req, res) => {
  const { settings } = req.body;

  // Parse as JSON (never arbitrary serialization)
  // JSON.parse is safe - it only creates data, never executes code
  const settingsSchema = {
    type: 'object',
    properties: {
      theme: { type: 'string', enum: ['light', 'dark', 'auto'] },
      notifications: { type: 'boolean' },
      fontSize: { type: 'integer', minimum: 10, maximum: 24 }
    },
