  };

  const validateSettings = ajv.compile(settingsSchema);

  if (!validateSettings(settings)) {
    return res.status(400).json({ 
      error: 'Invalid settings',
      details: validateSettings.errors 
    });
  }

  // Safe to use validated settings
  res.json({ success: true, settings });
});

app.listen(3000);
```

**Key Security Controls**:
- **Never deserialize untrusted data**: Use JSON.parse() which only creates data structures, never executes code
- **Cryptographic signatures**: JWTs ensure data integrity and authenticity - attackers cannot forge valid tokens
- **Strict schema validation**: AJV with additionalProperties: false prevents unexpected fields
- **Algorithm pinning**: Explicitly specify `algorithms: ['HS256']` to prevent algorithm confusion attacks

Great question - this is a common challenge in microservices architectures. The solution is to use safe serialization formats with explicit type handling and allowlisting, never arbitrary code execution during deserialization.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');

const app = express();
app.use(express.json({ limit: '1mb' }));

// HMAC key for inter-service communication
const SERVICE_SIGNING_KEY = process.env.SERVICE_SIGNING_KEY;

// Type-safe serialization with explicit type markers
class SafeSerializer {
  // Allowlist of types that can be serialized/deserialized
  static ALLOWED_TYPES = new Set(['Date', 'RegExp', 'Buffer', 'Map', 'Set']);

  // Custom classes must be registered explicitly
  static registeredClasses = new Map();

  static registerClass(name, constructor, validator) {
    if (typeof constructor !== 'function') {
      throw new Error('Constructor must be a function');
    }
    if (typeof validator !== 'function') {
      throw new Error('Validator must be a function');
    }
    this.registeredClasses.set(name, { constructor, validator });
  }

  static serialize(obj) {
    const serialized = JSON.stringify(obj, (key, value) => {
      if (value instanceof Date) {
        return { __type: 'Date', __value: value.toISOString() };
      }
      if (value instanceof RegExp) {
        // Only serialize safe regex patterns
        if (this.isRegexSafe(value)) {
          return { 
            __type: 'RegExp', 
            __value: { source: value.source, flags: value.flags }
          };
        }
        throw new Error('Unsafe regex pattern detected');
      }
      if (value instanceof Buffer) {
        return { __type: 'Buffer', __value: value.toString('base64') };
      }
      if (value instanceof Map) {
        return { __type: 'Map', __value: Array.from(value.entries()) };
      }
      if (value instanceof Set) {
        return { __type: 'Set', __value: Array.from(value) };
      }

      // Handle registered custom classes
      const className = value?.constructor?.name;
      if (className && this.registeredClasses.has(className)) {
        const { validator } = this.registeredClasses.get(className);
        const data = value.toJSON ? value.toJSON() : { ...value };
        if (!validator(data)) {
          throw new Error(`Invalid ${className} data`);
        }
        return { __type: className, __value: data };
      }

      return value;
    });

    return serialized;
  }

  static deserialize(jsonString, maxDepth = 10) {
    // Parse with depth limiting to prevent DoS
    const parsed = JSON.parse(jsonString);

    return this.reviveTypes(parsed, 0, maxDepth);
  }

  static reviveTypes(value, depth, maxDepth) {
    if (depth > maxDepth) {
      throw new Error('Maximum object depth exceeded');
    }

    if (value === null || typeof value !== 'object') {
      return value;
    }

    // Handle typed objects
    if (value.__type && value.__value !== undefined) {
      const typeName = value.__type;

      if (!this.ALLOWED_TYPES.has(typeName) && 
          !this.registeredClasses.has(typeName)) {
        throw new Error(`Unknown or disallowed type: ${typeName}`);
      }

      switch (typeName) {
        case 'Date':
          const dateValue = new Date(value.__value);
          if (isNaN(dateValue.getTime())) {
            throw new Error('Invalid date value');
          }
          return dateValue;

        case 'RegExp':
          // Validate regex before creating
          if (!this.isRegexPatternSafe(value.__value.source)) {
            throw new Error('Unsafe regex pattern');
          }
          return new RegExp(value.__value.source, value.__value.flags);

        case 'Buffer':
          return Buffer.from(value.__value, 'base64');

        case 'Map':
          return new Map(
            value.__value.map(([k, v]) => [
              this.reviveTypes(k, depth + 1, maxDepth),
              this.reviveTypes(v, depth + 1, maxDepth)
            ])
          );

        case 'Set':
          return new Set(
            value.__value.map(v => this.reviveTypes(v, depth + 1, maxDepth))
          );

        default:
          // Handle registered custom classes
          if (this.registeredClasses.has(typeName)) {
            const { constructor, validator } = this.registeredClasses.get(typeName);
            if (!validator(value.__value)) {
              throw new Error(`Invalid ${typeName} data`);
            }
            return new constructor(value.__value);
          }
      }
    }

    // Recursively handle arrays and objects
    if (Array.isArray(value)) {
      return value.map(v => this.reviveTypes(v, depth + 1, maxDepth));
    }

    const result = {};
    for (const [k, v] of Object.entries(value)) {
      result[k] = this.reviveTypes(v, depth + 1, maxDepth);
    }
    return result;
  }

  // Detect ReDoS-vulnerable patterns
  static isRegexSafe(regex) {
    return this.isRegexPatternSafe(regex.source);
  }

  static isRegexPatternSafe(pattern) {
    // Reject patterns known to cause catastrophic backtracking
    const dangerousPatterns = [
      /\(.+\)\+\+/,      // Nested quantifiers
      /\(.+\)\*\*/,
      /\(.+\)\{\d+,\}\{/,
      /\(\?!.*\).*\1/,   // Backreferences after lookahead
    ];

    for (const dangerous of dangerousPatterns) {
      if (dangerous.test(pattern)) {
        return false;
      }
    }

    // Limit pattern complexity
    if (pattern.length > 100) {
      return false;
    }

    return true;
  }
}

// Secure inter-service message envelope
class SecureEnvelope {
  static sign(payload, key = SERVICE_SIGNING_KEY) {
    const serialized = SafeSerializer.serialize(payload);
    const timestamp = Date.now();
    const nonce = crypto.randomBytes(16).toString('hex');

    const signatureBase = `${timestamp}.${nonce}.${serialized}`;
    const signature = crypto
      .createHmac('sha256', key)
      .update(signatureBase)
      .digest('hex');

    return {
      payload: serialized,
      timestamp,
      nonce,
      signature
    };
  }

  static verify(envelope, key = SERVICE_SIGNING_KEY, maxAgeMs = 300000) {
    const { payload, timestamp, nonce, signature } = envelope;

    // Verify timestamp (prevent replay attacks)
    const age = Date.now() - timestamp;
    if (age < 0 || age > maxAgeMs) {
      throw new Error('Message expired or from the future');
    }

    // Verify signature
    const signatureBase = `${timestamp}.${nonce}.${payload}`;
    const expectedSignature = crypto
      .createHmac('sha256', key)
      .update(signatureBase)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(signature, 'hex'),
      Buffer.from(expectedSignature, 'hex')
    )) {
      throw new Error('Invalid signature');
    }

    // Safe to deserialize after verification
    return SafeSerializer.deserialize(payload);
  }
}

// Register custom classes with validators
class UserPreferences {
  constructor(data) {
    this.theme = data.theme;
    this.language = data.language;
    this.createdAt = data.createdAt;
  }

  toJSON() {
    return {
      theme: this.theme,
      language: this.language,
      createdAt: this.createdAt
    };
  }
}

const preferencesValidator = (data) => {
  return typeof data.theme === 'string' &&
         ['light', 'dark', 'auto'].includes(data.theme) &&
         typeof data.language === 'string' &&
         /^[a-z]{2}(-[A-Z]{2})?$/.test(data.language);
};

SafeSerializer.registerClass('UserPreferences', UserPreferences, preferencesValidator);

// API endpoint for inter-service communication
app.post('/api/internal/sync-data', (req, res) => {
  try {
    // Verify the signed envelope
    const data = SecureEnvelope.verify(req.body);

    console.log('Received verified data:', {
      receivedAt: new Date().toISOString(),
      dataTypes: Object.keys(data)
    });

    // Process the safely deserialized data
    res.json({ success: true, processed: true });

  } catch (err) {
    console.error('Envelope verification failed:', err.message);
    res.status(400).json({ error: 'Invalid or tampered data' });
  }
});

